content.text:
.layout {
  display: grid;
  grid-template-columns: 200px 1fr 1fr;   /* fixed | flexible | flexible */
  grid-template-rows: auto 1fr auto;       /* header | content | footer */
  gap: 16px;
}

.grid {
  /* Without repeat */
  grid-template-columns: 1fr 1fr 1fr 1fr;

  /* With repeat — equivalent */
  grid-template-columns: repeat(4, 1fr);

  /* Mixed */
  grid-template-columns: 200px repeat(3, 1fr);
}

.card-grid {
  display: grid;
  /* Creates as many ≥200px columns as fit */
  grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
  gap: 16px;
}

/* auto-fit collapses empty tracks; auto-fill keeps them */
.auto-fit-grid {
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
}

.item-a {
  grid-column: 1 / 3;   /* spans columns 1 and 2 */
  grid-row: 1 / 2;      /* occupies row 1 */
}

.item-b {
  grid-column: 2 / -1;  /* from column 2 to the last line */
}

.item-c {
  grid-column: span 2;  /* shorthand: span 2 tracks from current position */
  grid-row: span 3;
}

.page {
  display: grid;
  grid-template-columns: 220px 1fr;
  grid-template-rows: 60px 1fr 44px;
  grid-template-areas:
    "header  header"
    "sidebar main"
    "footer  footer";
  gap: 0;
}

.page-header  { grid-area: header; }
.page-sidebar { grid-area: sidebar; }
.page-main    { grid-area: main; }
.page-footer  { grid-area: footer; }

.grid {
  gap: 16px;           /* same for rows and columns */
  row-gap: 24px;       /* row gap only */
  column-gap: 12px;    /* column gap only */
}

.grid {
  display: grid;
  grid-template-columns: repeat(3, 120px);
  justify-content: center;    /* center the 3 narrow tracks in a wide container */
  align-items: stretch;       /* items fill their row track height */
}

.grid__logo {
  justify-self: start;        /* override: align left within its cell */
  align-self: center;
}

.grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  grid-auto-rows: minmax(80px, auto); /* implicit rows are at least 80px */
}

/* Items placed in columns beyond grid-template-columns get auto tracks */
.grid {
  grid-auto-flow: column;  /* add new columns instead of rows */
  grid-auto-columns: 200px;
}

.masonry-like {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  grid-auto-flow: row dense;  /* fill holes with smaller items */
}

.card-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  grid-template-rows: auto 1fr auto; /* header | body | footer */
}

.card {
  display: grid;
  grid-row: span 3;
  grid-template-rows: subgrid; /* inherit parent's row tracks */
}

.card__header { grid-row: 1; }
.card__body   { grid-row: 2; } /* stretches to match tallest card */
.card__footer { grid-row: 3; } /* always at the same row across all cards */

:host {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
  gap: 24px;
}

