        "nav    main"
        "footer footer";
      min-height: 100vh;
    }
    .layout__header { grid-area: header; }
    .layout__nav    { grid-area: nav; }
    .layout__main   { grid-area: main; }
    .layout__footer { grid-area: footer; }
