.product-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(260px, 1fr));
  gap: 24px;
  padding: 24px;
}

.grid-fill {
  /* Keeps empty tracks — useful for alignment when items vary */
  grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
}

.grid-fit {
  /* Collapses empty tracks — items stretch to fill */
  grid-template-columns: repeat(auto-fit, minmax(260px, 1fr));
}

.layout {
  display: grid;
  grid-template-columns:
    [full-start]  16px
    [content-start] 1fr
    [content-end] 16px
    [full-start];

  grid-template-rows:
    [header-start] 60px [header-end main-start]
    1fr
    [main-end footer-start] 48px [footer-end];
}

.hero {
  grid-column: full-start / full-end;  /* bleeds to edges */
}

.article {
  grid-column: content-start / content-end;  /* contained */
  grid-row: main-start / main-end;
}

/* dashboard.component.scss */
:host {
  display: grid;
  grid-template-columns: 240px 1fr;
  grid-template-rows: 56px 1fr;
  grid-template-areas:
    "sidebar topbar"
    "sidebar content";
  height: 100vh;
  overflow: hidden;
}

.sidebar   { grid-area: sidebar; overflow-y: auto; }
.topbar    { grid-area: topbar; }
.content   { grid-area: content; overflow-y: auto; padding: 24px; }

@media (max-width: 768px) {
  :host {
    grid-template-columns: 1fr;
    grid-template-rows: 56px 1fr 56px;
    grid-template-areas:
      "topbar"
      "content"
      "sidebar";
  }
  .sidebar {
    overflow-x: auto;
    overflow-y: hidden;
    display: flex;  /* horizontal tab bar on mobile */
  }
}

