  selector: 'app-card-grid',
  template: `<ng-content></ng-content>`,
  styles: [`
    :host {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(var(--card-min-width, 280px), 1fr));
      gap: var(--card-gap, 24px);
    }
  `]
})
export class CardGridComponent {}

.grid {
  display: grid;
  grid-template-columns: 1fr 300px;
}

.main {
  /* Default min-width: auto can cause overflow if content is wide */
  min-width: 0; /* fix: allow the 1fr track to shrink */
  overflow: hidden;
}

.grid {
  /* Use minmax(0, 1fr) instead of 1fr to prevent overflow from the start */
  grid-template-columns: minmax(0, 1fr) 300px;
}

.holy-grail {
  display: grid;
  grid-template:
    "header" 60px
    "nav main aside" 1fr
    "footer" 44px
    / 180px 1fr 180px;
  min-height: 100vh;
}
.header { grid-area: header; }
.nav    { grid-area: nav; }
.main   { grid-area: main; }
.aside  { grid-area: aside; }
.footer { grid-area: footer; }

.masonry {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
  grid-auto-rows: 8px;        /* fine-grained rows for span calculation */
  grid-auto-flow: row dense;  /* fill gaps */
}

/* JS sets --span dynamically based on image height */
.masonry-item {
  grid-row: span var(--span, 30);
}

.article-body {
  display: grid;
  grid-template-columns:
    [full-start] 1fr
    [content-start] min(65ch, 100% - 32px)
    [content-end] 1fr
    [full-end];
}

.article-body > * {
  grid-column: content;         /* default: centered column */
}

.article-body > .full-bleed {
  grid-column: full;             /* edge-to-edge */
  width: 100%;
}

.debug-grid {
  background-image:
    repeating-linear-gradient(
      to right,
      rgba(100, 100, 255, 0.08) 0px,
      rgba(100, 100, 255, 0.08) 1px,
      transparent 1px,
      transparent calc(100% / 12)
    );
  background-size: 100% 100%;
}
